const raw = $input.first().json;

if (raw.input) {
  const parsed = typeof raw.input === 'string' ? JSON.parse(raw.input) : raw.input;
  return [{ json: parsed }];
}

return [{ json: raw }];

const items = $input.all();
// console.log('items:', items.length);

function clean(val) {
  if (val === null || val === undefined) return '';
  return String(val).trim();
}

return items
  .map(item => {
    const row = item.json;
    const status = clean(row.status).toLowerCase();

    return {
      json: {
        id: clean(row.id) || `${Date.now()}-${Math.floor(Math.random()*1000)}`,
        titulo: clean(row.titulo),
        prazo: row.prazo || null,
        observacao: clean(row.observacao),
        status: clean(row.status),
        status_norm: status
      }
    };
  })
  .filter(item => {
    return item.json.status_norm !== 'concluída' &&
           item.json.status_norm !== 'concluida';
  });
